75	// Check for input events that would normally block.
76	void poll_inputs(struct processor *proc)
77	{
78	    char interrupt_id;
79	
80	    // An external process can send interrupts to the emulator by writing to a
81	    // named pipe. Poll the pipe to determine if any messages are pending. If
82	    // so, call into the processor to dispatch.
83	    if (recv_interrupt_fd > 0 && can_read_file_descriptor(recv_interrupt_fd))
84	    {
85	        if (read(recv_interrupt_fd, &interrupt_id, 1) < 1)
86	        {
87	            perror("poll_inputs: read failed");
88	            exit(1);
89	        }
90	
91	        if (interrupt_id > 16)
92	        {
93	            fprintf(stderr, "Received invalidate interrupt ID %d\n", interrupt_id);
94	            return; // Ignore invalid interrupt IDs
95	        }
96	
97	        raise_interrupt(proc, 1 << interrupt_id);
98	    }
99	
100	    // Typing in the terminal that launched emulator will emulate serial
101	    // transfers.
102	    if (can_read_file_descriptor(STDIN_FILENO))
103	    {
104	        char inbuf[64];
105	        int got;
106	        int i;
107	
108	        got = read(STDIN_FILENO, inbuf, sizeof(inbuf));
109	        for (i = 0; i < got; i++)
110	            enqueue_serial_char(inbuf[i]);
111	    }
112	}
