114	void send_host_interrupt(uint32_t num)
115	{
116	    char c = (char) num;
117	
118	    if (send_interrupt_fd < 0)
119	        return;
120	
121	    if (write(send_interrupt_fd, &c, 1) < 1)
122	    {
123	        perror("send_host_interrupt: write failed");
124	        exit(1);
125	    }
126	}
