142	int main(int argc, char *argv[])
143	{
144	    struct processor *proc;
145	    int option;
146	    bool enable_memory_dump = false;
147	    uint32_t mem_dump_base = 0;
148	    uint32_t mem_dump_length = 0;
149	    char *mem_dump_filename = NULL;
150	    size_t mem_dump_filename_len = 0;
151	    bool verbose = false;
152	    uint32_t fb_width = 640;
153	    uint32_t fb_height = 480;
154	    bool block_device_open = false;
155	    bool enable_fb_window = false;
156	    uint32_t threads_per_core = 4;
157	    uint32_t num_cores = 1;
158	    char *separator;
159	    uint32_t memory_size = 0x1000000;
160	    const char *shared_memory_file = NULL;
161	    struct stat st;
162	    bool random_thread_sched = false;
163	    struct termios new_tconfig;
164	
165	    enum
166	    {
167	        MODE_NORMAL,
168	        MODE_COSIMULATION,
169	        MODE_GDB_REMOTE_DEBUG
170	    } mode = MODE_NORMAL;
171	
172	    while ((option = getopt(argc, argv, "f:d:vm:b:t:p:c:r:s:i:o:a")) != -1)
173	    {
174	        switch (option)
175	        {
176	            case 'v':
177	                verbose = true;
178	                break;
179	
180	            case 'r':
181	                screen_refresh_rate = parse_num_arg(optarg);
182	                break;
183	
184	            case 'f':
185	                enable_fb_window = true;
186	                separator = strchr(optarg, 'x');
187	                if (!separator)
188	                {
189	                    fprintf(stderr, "Invalid frame buffer size %s\n", optarg);
190	                    return 1;
191	                }
192	
193	                fb_width = parse_num_arg(optarg);
194	                fb_height = parse_num_arg(separator + 1);
195	                break;
196	
197	            case 'm':
198	                if (strcmp(optarg, "normal") == 0)
199	                    mode = MODE_NORMAL;
200	                else if (strcmp(optarg, "cosim") == 0)
201	                    mode = MODE_COSIMULATION;
202	                else if (strcmp(optarg, "gdb") == 0)
203	                    mode = MODE_GDB_REMOTE_DEBUG;
204	                else
205	                {
206	                    fprintf(stderr, "Unkown execution mode %s\n", optarg);
207	                    return 1;
208	                }
209	
210	                break;
211	
212	            case 'd':
213	                // Memory dump, of the form: filename,start,length
214	                separator = strchr(optarg, ',');
215	                if (separator == NULL)
216	                {
217	                    fprintf(stderr, "bad format for memory dump\n");
218	                    usage();
219	                    return 1;
220	                }
221	
222	                mem_dump_filename_len = (size_t)(separator - optarg);
223	                mem_dump_filename = (char*) malloc(mem_dump_filename_len + 1);
224	                strncpy(mem_dump_filename, optarg, mem_dump_filename_len);
225	                mem_dump_filename[mem_dump_filename_len] = '\0';
226	                mem_dump_base = parse_num_arg(separator + 1);
227	
228	                separator = strchr(separator + 1, ',');
229	                if (separator == NULL)
230	                {
231	                    fprintf(stderr, "bad format for memory dump\n");
232	                    usage();
233	                    free(mem_dump_filename);
234	                    return 1;
235	                }
236	
237	                mem_dump_length = parse_num_arg(separator + 1);
238	                enable_memory_dump = true;
239	                break;
240	
241	            case 'b':
242	                if (open_sdmmc_device(optarg) < 0)
243	                    return 1;
244	
245	                block_device_open = true;
246	                break;
247	
248	            case 'c':
249	                memory_size = parse_num_arg(optarg);
250	                break;
251	
252	            case 't':
253	                threads_per_core = parse_num_arg(optarg);
254	                if (threads_per_core < 1 || threads_per_core > 32)
255	                {
256	                    fprintf(stderr, "Total threads must be between 1 and 32\n");
257	                    return 1;
258	                }
259	
260	                break;
261	
262	            case 'p':
263	                num_cores = parse_num_arg(optarg);
264	                if (num_cores < 1)
265	                {
266	                    // XXX Should there be a maximum?
267	                    fprintf(stderr, "Total cores must 1 or greater\n");
268	                    return 1;
269	                }
270	
271	                break;
272	
273	            case 's':
274	                shared_memory_file = optarg;
275	                break;
276	
277	            case 'i':
278	                recv_interrupt_fd = open(optarg, O_RDWR);
279	                if (recv_interrupt_fd < 0)
280	                {
281	                    perror("main: failed to open receive interrupt pipe");
282	                    return 1;
283	                }
284	
285	                if (fstat(recv_interrupt_fd, &st) < 0)
286	                {
287	                    perror("main: stat failed on receive interrupt pipe");
288	                    return 1;
289	                }
290	
291	                if ((st.st_mode & S_IFMT) != S_IFIFO)
292	                {
293	                    fprintf(stderr, "%s is not a pipe\n", optarg);
294	                    return 1;
295	                }
296	
297	                break;
298	
299	            case 'o':
300	                send_interrupt_fd = open(optarg, O_RDWR);
301	                if (send_interrupt_fd < 0)
302	                {
303	                    perror("main: failed to open send interrupt pipe");
304	                    return 1;
305	                }
306	
307	                if (fstat(send_interrupt_fd, &st) < 0)
308	                {
309	                    perror("main: stat failed on send interrupt pipe");
310	                    return 1;
311	                }
312	
313	                if ((st.st_mode & S_IFMT) != S_IFIFO)
314	                {
315	                    fprintf(stderr, "%s is not a pipe\n", optarg);
316	                    return 1;
317	                }
318	
319	                break;
320	
321	            case 'a':
322	                random_thread_sched = true;
323	                break;
324	
325	            case '?':
326	                usage();
327	                return 1;
328	        }
329	    }
330	
331	    if (optind == argc)
332	    {
333	        fprintf(stderr, "No image filename specified\n");
334	        usage();
335	        return 1;
336	    }
337	
338	    seed_random(current_time_us());
339	
340	    // Don't randomize memory for cosimulation mode, because
341	    // memory is checked against the hardware model to ensure a match
342	    proc = init_processor(memory_size, num_cores, threads_per_core,
343	                          mode != MODE_COSIMULATION, shared_memory_file);
344	    if (proc == NULL)
345	        return 1;
346	
347	    if (load_hex_file(proc, argv[optind]) < 0)
348	    {
349	        fprintf(stderr, "Error reading image %s\n", argv[optind]);
350	        return 1;
351	    }
352	
353	    init_device(proc);
354	
355	    if (enable_fb_window)
356	    {
357	        if (init_frame_buffer(fb_width, fb_height) < 0)
358	            return 1;
359	    }
360	
361	    if (random_thread_sched)
362	        enable_random_thread_sched(proc);
363	
364	    // Set up terminal for unbuffered operation for proper serial input.
365	    // tcgetattr will fail if we are not running in a terminal (for example,
366	    // input and output are pipes, which many tests do). In this case,
367	    // skip the rest of the terminal initialization.
368	    if (tcgetattr(STDIN_FILENO, &original_tconfig) == 0)
369	    {
370	        // Set up these handlers to restore the terminal state on exit.
371	        if (signal(SIGINT, handle_quit_signal) == SIG_ERR)
372	        {
373	            perror("error setting up signal handler");
374	            tcsetattr(STDIN_FILENO, TCSANOW, &original_tconfig);
375	            exit(1);
376	        }
377	
378	        if (signal(SIGTERM, handle_quit_signal) == SIG_ERR)
379	        {
380	            perror("error setting up signal handler");
381	            tcsetattr(STDIN_FILENO, TCSANOW, &original_tconfig);
382	            exit(1);
383	        }
384	
385	        if (atexit(shutdown_cleanup) < 0)
386	        {
387	            perror("error setting up atexit handler");
388	            tcsetattr(STDIN_FILENO, TCSANOW, &original_tconfig);
389	            exit(1);
390	        }
391	
392	        new_tconfig = original_tconfig;
393	        new_tconfig.c_lflag = ISIG | TOSTOP;  // Disable local echo, canonical input
394	        if (tcsetattr(STDIN_FILENO, TCSANOW, &new_tconfig) < 0)
395	            perror("tcsetattr");
396	    }
397	
398	    switch (mode)
399	    {
400	        case MODE_NORMAL:
401	            if (verbose)
402	                enable_tracing(proc);
403	
404	            dbg_set_stop_on_fault(proc, false);
405	            if (enable_fb_window)
406	            {
407	                while (execute_instructions(proc, screen_refresh_rate))
408	                {
409	                    update_frame_buffer(proc);
410	                    poll_fb_window_event();
411	                    poll_inputs(proc);
412	                }
413	            }
414	            else
415	            {
416	                while (execute_instructions(proc, 1000000))
417	                    poll_inputs(proc);
418	            }
419	
420	            break;
421	
422	        case MODE_COSIMULATION:
423	            dbg_set_stop_on_fault(proc, false);
424	            if (run_cosimulation(proc, verbose) < 0)
425	                return 1;	// Failed
426	
427	            break;
428	
429	        case MODE_GDB_REMOTE_DEBUG:
430	            dbg_set_stop_on_fault(proc, true);
431	            remote_gdb_main_loop(proc, enable_fb_window);
432	            break;
433	    }
434	
435	    if (enable_memory_dump)
436	        write_memory_to_file(proc, mem_dump_filename, mem_dump_base, mem_dump_length);
437	
438	    free(mem_dump_filename);
439	
440	    dump_instruction_stats(proc);
441	    if (block_device_open)
442	        close_sdmmc_device();
443	
444	    if (is_stopped_on_fault(proc))
445	        return 1;
446	
447	    return 0;
448	}
