28	static inline uint32_t hex_digit_val(char ch) {
29	    if (ch >= '0' && ch <= '9')
30	        return (uint32_t) (ch - '0');
31	    else if (ch >= 'a' && ch <= 'f')
32	        return (uint32_t) (ch - 'a' + 10);
33	    else if (ch >= 'A' && ch <= 'F')
34	        return (uint32_t) (ch - 'A' + 10);
35	    else
36	        return UINT32_MAX;
37	}
