39	int parse_hex_vector(const char *str, uint32_t *vector_values, bool endian_swap)
40	{
41	    const char *c = str;
42	    int lane;
43	    int digit;
44	    uint32_t lane_value;
45	
46	    for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
47	    {
48	        lane_value = 0;
49	        for (digit = 0; digit < 8; digit++)
50	        {
51	            uint32_t digit_val = hex_digit_val(*c);
52	            if (digit_val == UINT32_MAX)
53	            {
54	                printf("bad character %c in hex vector\n", *c);
55	                return -1;
56	            }
57	            else
58	                lane_value = (lane_value << 4) | digit_val;
59	
60	            if (*c == '\0')
61	            {
62	                printf("Error parsing hex vector\n");
63	                break;
64	            }
65	            else
66	                c++;
67	        }
68	
69	        vector_values[lane] = endian_swap ? endian_swap32(lane_value) : lane_value;
70	    }
71	
72	    return 0;
73	}
74	
75	void seed_random(uint64_t value)
76	{
77	    int stir;
78	
79	    random_state[0] = value;
80	    random_state[1] = value;
81	    for (stir = 0; stir < 5; stir++)
82	        next_random();
83	}
84	
85	// xorshift128+ random number generator
86	// https://arxiv.org/abs/1404.0390
87	uint64_t next_random(void)
88	{
89		uint64_t x = random_state[0];
90		uint64_t const y = random_state[1];
91		random_state[0] = y;
92		x ^= x << 23;
93		random_state[1] = x ^ y ^ (x >> 17) ^ (y >> 26);
94		return random_state[1] + y;
95	}
