104	//
105	// Format is defined in IEEE 1364-2001, section 17.2.8
106	//
107	int read_hex_file(const char *filename, uint32_t *memory, uint32_t memory_size)
108	{
109	    FILE *file;
110	    int line_num = 1;
111	    uint32_t number_value;
112	    int push_back_char = -1;
113	    bool done = false;
114	    uint32_t address = 0;
115	
116	    enum {
117	        SCAN_SPACE,
118	        SCAN_SLASH,
119	        SCAN_ADDRESS,
120	        SCAN_NUMBER,
121	        SCAN_MULTI_LINE_COMMENT,
122	        SCAN_ASTERISK,
123	        SCAN_SINGLE_LINE_COMMENT
124	    } state = SCAN_SPACE;
125	
126	    file = fopen(filename, "r");
127	    if (file == NULL)
128	    {
129	        perror("read_hex_file: error opening hex file");
130	        return -1;
131	    }
132	
133	    while (!done) {
134	        int ch;
135	        if (push_back_char != -1)
136	        {
137	            ch = push_back_char;
138	            push_back_char = -1;
139	        }
140	        else
141	            ch = fgetc(file);
142	
143	        switch (state)
144	        {
145	            case SCAN_SPACE:
146	                if (ch == EOF)
147	                    done = true;
148	                else if (ch == '/')
149	                    state = SCAN_SLASH;
150	                else if (ch == '@')
151	                {
152	                    state = SCAN_ADDRESS;
153	                    number_value = 0;
154	                }
155	                else if (isxdigit(ch))
156	                {
157	                    number_value = hex_digit_val(ch);
158	                    state = SCAN_NUMBER;
159	                }
160	                else if (!isspace(ch))
161	                {
162	                    fprintf(stderr, "read_hex_file: Invalid character %c in line %d\n", ch, line_num);
163	                    fclose(file);
164	                    return -1;
165	                } else if (ch == '\n')
166	                    line_num++;
167	
168	                break;
169	
170	            case SCAN_SLASH:
171	                if (ch == '*')
172	                    state = SCAN_MULTI_LINE_COMMENT;
173	                else if (ch == '/')
174	                    state = SCAN_SINGLE_LINE_COMMENT;
175	                else
176	                {
177	                    fprintf(stderr, "read_hex_file: Invalid character %c in line %d\n", ch, line_num);
178	                    fclose(file);
179	                    return -1;
180	                }
181	
182	                break;
183	
184	            case SCAN_SINGLE_LINE_COMMENT:
185	                if (ch == '\n') {
186	                    state = SCAN_SPACE;
187	                } else if (ch == EOF) {
188	                    done = true;
189	                }
190	
191	                break;
192	
193	            case SCAN_MULTI_LINE_COMMENT:
194	                if (ch == '*')
195	                    state = SCAN_ASTERISK;
196	                else if (ch == EOF)
197	                {
198	                    fprintf(stderr, "read_hex_file: Missing */ at end of file\n");
199	                    fclose(file);
200	                    return -1;
201	                }
202	
203	                break;
204	
205	            case SCAN_ASTERISK:
206	                if (ch == '/')
207	                    state = SCAN_SPACE;
208	                else if (ch == EOF)
209	                {
210	                    fprintf(stderr, "read_hex_file: Missing */ at end of file\n");
211	                    fclose(file);
212	                    return -1;
213	                }
214	
215	                break;
216	
217	            case SCAN_NUMBER:
218	                if (isxdigit(ch))
219	                {
